"""
Sample 1 — Article CRUD routes (Gen 1 mutant).

Design decisions (deliberate variations from other samples):
- Direct top-level import from models (no lazy import — simpler, trusts
  app.py to have already initialised db before this module is loaded).
- Validation as a standalone pure function _validate_article_input returning
  (is_valid, error_message).  Separates "is the payload good?" from "build
  the response", making it easy to test the validator in isolation.
- Response builders _ok() / _error() for consistent envelope formatting.
- try/except around db.add+db.commit so DB-level failures surface as 500.
- List endpoint uses .order_by(Article.id.asc()) for stable, predictable
  ordering that matches the auto-increment sequence.
"""

from flask import Blueprint, request, jsonify
from models import Article, db

article_bp = Blueprint('article_bp', __name__)


# ---------------------------------------------------------------------------
# Response helpers
# ---------------------------------------------------------------------------

def _ok(data, status=200):
    """Wrap a successful payload in the standard envelope."""
    return jsonify({"status": "ok", "data": data}), status


def _error(message, status=400):
    """Wrap an error message in the standard envelope."""
    return jsonify({"status": "error", "message": message}), status


# ---------------------------------------------------------------------------
# Validation (pure function — no side-effects, no DB access)
# ---------------------------------------------------------------------------

def _validate_article_input(payload):
    """
    Validate the raw JSON payload for article creation.

    Returns:
        (True, None)            when valid
        (False, error_message)  when invalid
    """
    if not isinstance(payload, dict):
        return False, "Request body must be a JSON object"

    title = payload.get("title")
    body = payload.get("body")

    # Presence checks — covers missing key, explicit null, and non-string types
    if title is None:
        return False, "title is required"
    if body is None:
        return False, "body is required"

    if not isinstance(title, str) or not isinstance(body, str):
        return False, "title and body must be strings"

    # Blank / whitespace-only checks
    if title.strip() == "":
        return False, "title must not be blank"
    if body.strip() == "":
        return False, "body must not be blank"

    return True, None


# ---------------------------------------------------------------------------
# Article serializer
# ---------------------------------------------------------------------------

def _serialize_article(article):
    """Convert an Article ORM object to a plain dict."""
    return {
        "id": article.id,
        "title": article.title,
        "body": article.body,
    }


# ---------------------------------------------------------------------------
# Routes
# ---------------------------------------------------------------------------

@article_bp.route("/articles", methods=["POST"])
def create_article():
    """Create a new article."""
    payload = request.get_json(silent=True)

    # Defensive: get_json returns None for non-JSON bodies
    if payload is None:
        return _error("Request body must be valid JSON", 400)

    valid, msg = _validate_article_input(payload)
    if not valid:
        return _error(msg, 400)

    article = Article(title=payload["title"].strip(), body=payload["body"].strip())

    try:
        db.session.add(article)
        db.session.commit()
    except Exception:
        db.session.rollback()
        return _error("Failed to create article", 500)

    return _ok(_serialize_article(article), status=201)


@article_bp.route("/articles", methods=["GET"])
def list_articles():
    """Return all articles ordered by id ascending."""
    articles = Article.query.order_by(Article.id.asc()).all()
    return _ok([_serialize_article(a) for a in articles])


@article_bp.route("/articles/<int:article_id>", methods=["GET"])
def get_article(article_id):
    """Return a single article by id, or 404."""
    article = Article.query.get(article_id)
    if article is None:
        return _error("Article not found", 404)
    return _ok(_serialize_article(article))

