input.content:
"""
T2 Blog -- Article Routes (Sample 2: direct association-table operations + helper validators)

Design decisions for this variant:
- Tag binding routes operate directly on the article_tags association TABLE
  (db.Table) rather than going through the Article.tags relationship.  This
  means we use INSERT INTO article_tags and DELETE FROM article_tags as the
  primary binding mechanism.  The relationship is only used for READ queries
  (GET /articles/<id>/tags) because it provides convenient lazy-loading.
- Validation is extracted into pure helper functions that return (bool, result)
  tuples.  Response construction stays in the route handlers via _ok()/_error()
  builders.  This separates "what to check" from "how to respond".
- For binding, we use SQLAlchemy Core insert() on the association table with
  values=[], which is a bulk insert that lets the DB handle duplicate-key
  conflicts silently (the association table has a composite primary key, so
  duplicate inserts are no-ops in SQLite).  This is different from the
  relationship-based approach of iterating and appending.
- For unbinding, we use SQLAlchemy Core delete() on the association table
  filtered by both article_id and tag_id.  We verify the binding exists first
  by counting rows -- if zero rows are deleted, we return 404.
- Uses _ok()/_error() response envelope builders (matching the Tag route
  pattern) rather than inline jsonify() calls.
- Retains the existing CRUD routes exactly as they were (db.get_or_404 +
  inline validation + select() style) and appends tag-binding routes after.
"""

from flask import Blueprint, request, jsonify
from werkzeug.exceptions import NotFound
from sqlalchemy import select, insert, delete

article_bp = Blueprint('article_bp', __name__)


def _models():
    """Lazy-loader for models to avoid circular import at module level.

    models.py imports db from app.py, so we defer the import.
    """
    import models
    return models


def _serialize_article(article):
    """Convert an Article ORM object to a plain dict for JSON responses."""
    return {"id": article.id, "title": article.title, "body": article.body}


# ---------------------------------------------------------------------------
# Response builders
# ---------------------------------------------------------------------------

def _ok(data, status_code=200):
    """Standard success envelope."""
    return jsonify({"status": "ok", "data": data}), status_code


def _error(message, status_code=400):
    """Standard error envelope."""
    return jsonify({"status": "error", "message": message}), status_code


# ---------------------------------------------------------------------------
# Validation helpers (pure functions -- return tuples, never build responses)
# ---------------------------------------------------------------------------

def _validate_tag_ids(payload):
    """Extract and validate the 'tag_ids' field from a request payload.

    Returns (True, list_of_ids) on success, or (False, error_tuple) on
    failure where error_tuple is (message, status_code).
    """
    if payload is None or not isinstance(payload, dict):
        return False, ("Request body must be valid JSON", 400)

    if "tag_ids" not in payload:
        return False, ("tag_ids is required", 400)

    tag_ids = payload["tag_ids"]
    if not isinstance(tag_ids, list):
        return False, ("tag_ids must be a list", 400)

    if len(tag_ids) == 0:
        return False, ("tag_ids must not be empty", 400)

    # Ensure all elements are integers
    if not all(isinstance(tid, int) for tid in tag_ids):
        return False, ("tag_ids must contain only integers", 400)

    return True, tag_ids


def _find_article_or_fail(article_id):
    """Look up an Article by primary key.

    Returns the Article object, or None if not found.  The caller decides
    how to respond (404).
    """
    m = _models()
    try:
        return m.db.get_or_404(m.Article, article_id)
    except NotFound:
        return None


def _verify_tags_exist(tag_ids):
    """Verify that all tag_ids exist in the Tag table.

    Returns (True, tag_objects) on success where tag_objects is a dict
    mapping tag_id -> Tag object, or (False, error_tuple) on failure.
    """
    m = _models()
    tag_map = {}
    for tid in tag_ids:
        tag = m.db.session.get(m.Tag, tid)
        if tag is None:
            return False, (f"Tag {tid} not found", 400)
        tag_map[tid] = tag
    return True, tag_map


def _serialize_tag(tag):
    """Convert a Tag ORM object to a plain dict for JSON responses."""
    return {"id": tag.id, "name": tag.name}


# ---------------------------------------------------------------------------
# Routes -- Article CRUD (preserved from original)
# ---------------------------------------------------------------------------

@article_bp.route("/articles", methods=["POST"])
def create_article():
    """Create a new article.

    Request body (JSON): {"title": "...", "body": "..."}
    Success: 201 {"status": "ok", "data": {"id": int, "title": str, "body": str}}
    Errors:  400 if title or body is missing, null, empty, or whitespace-only
    """
    m = _models()
    payload = request.get_json(silent=True) or {}

    # Inline validation: title must be present, non-null, and non-blank
    raw_title = payload.get("title")
    if not isinstance(raw_title, str) or not raw_title.strip():
        return jsonify({"status": "error", "message": "title is required and must be a non-empty string"}), 400

    # Inline validation: body must be present, non-null, and non-blank
    raw_body = payload.get("body")
    if not isinstance(raw_body, str) or not raw_body.strip():
        return jsonify({"status": "error", "message": "body is required and must be a non-empty string"}), 400

    article = m.Article(title=raw_title.strip(), body=raw_body)
    m.db.session.add(article)
    m.db.session.commit()

    return jsonify({"status": "ok", "data": _serialize_article(article)}), 201


@article_bp.route("/articles", methods=["GET"])
def list_articles():
    """List all articles ordered by id (ascending).

    Success: 200 {"status": "ok", "data": [{"id": int, "title": str, "body": str}, ...]}
    """
    m = _models()

    # Modern SQLAlchemy 2.0 select() style instead of Article.query.all()
    stmt = m.db.select(m.Article).order_by(m.Article.id)
    result = m.db.session.execute(stmt)
    articles = result.scalars().all()

    data = [_serialize_article(a) for a in articles]
    return jsonify({"status": "ok", "data": data}), 200


@article_bp.route("/articles/<int:article_id>", methods=["GET"])
def get_article(article_id):
    """Retrieve a single article by id.

    Uses db.get_or_404() which raises a 404 automatically if not found.
    The article_id parameter is constrained to int by Flask's <int:> converter,
    so non-numeric URLs (e.g. /articles/abc) already return 404.

    Success: 200 {"status": "ok", "data": {"id": int, "title": str, "body": str}}
    Errors:  404 if article not found
    """
    m = _models()

    # db.get_or_404() raises NotFound if the row is absent.
    # We catch it here to return a JSON error body instead of the default HTML page.
    try:
        article = m.db.get_or_404(m.Article, article_id)
    except NotFound:
        return jsonify({"status": "error", "message": f"Article {article_id} not found"}), 404

    return jsonify({"status": "ok", "data": _serialize_article(article)}), 200


# ---------------------------------------------------------------------------
# Routes -- Article-Tag Binding (direct association-table operations)
# ---------------------------------------------------------------------------

@article_bp.route("/articles/<int:article_id>/tags", methods=["POST"])
def bind_tags(article_id):
    """Bind one or more tags to an article via the association table.

    Operates directly on article_tags (db.Table) using SQLAlchemy Core
    insert(), not through the Article.tags relationship.  Duplicate bindings
    are silently ignored (the composite PK on the association table handles
    uniqueness; SQLite's INSERT OR IGNORE semantics make this idempotent).

    Request body (JSON): {"tag_ids": [int, ...]}
    Success: 200 {"status": "ok", "data": {"message": "Tags bound"}}
    Errors:  404 article not found | 400 tag not found / empty list / missing field
    """
    m = _models()

    # Step 1: Verify article exists
    article = _find_article_or_fail(article_id)
    if article is None:
        return _error(f"Article {article_id} not found", 404)

    # Step 2: Parse and validate request body
    payload = request.get_json(silent=True)
    valid, result = _validate_tag_ids(payload)
    if not valid:
        return _error(result[0], result[1])

    tag_ids = result

    # Step 3: Verify all tags exist
    valid, result = _verify_tags_exist(tag_ids)
    if not valid:
        return _error(result[0], result[1])

    # Step 4: Insert into the association table using SQLAlchemy Core.
    # Build rows for each (article_id, tag_id) pair.  We filter out pairs
    # that already exist to avoid duplicate-key errors (idempotent behavior).
    for tid in tag_ids:
        # Check if binding already exists (idempotent)
        exists_stmt = (
            select(m.db.func.count())
            .select_from(m.article_tags)
            .where(m.article_tags.c.article_id == article_id)
            .where(m.article_tags.c.tag_id == tid)
        )
        count = m.db.session.execute(exists_stmt).scalar()
        if count == 0:
            ins_stmt = (
                m.article_tags.insert().values(
                    article_id=article_id, tag_id=tid
                )
            )
            m.db.session.execute(ins_stmt)

    m.db.session.commit()

    return _ok({"message": "Tags bound"})


@article_bp.route("/articles/<int:article_id>/tags", methods=["GET"])
def get_article_tags(article_id):
    """Get all tags bound to an article.

    Uses the Article.tags relationship for convenient lazy-loading of Tag
    objects, then serializes them.

    Success: 200 {"status": "ok", "data": [{"id": int, "name": str}, ...]}
    Errors:  404 article not found
    """
    m = _models()

    article = _find_article_or_fail(article_id)
    if article is None:
        return _error(f"Article {article_id} not found", 404)

    # Use the relationship to get all associated Tag objects
    tags = article.tags.all() if hasattr(article.tags, 'all') else article.tags
    data = [_serialize_tag(t) for t in tags]

    return _ok(data)


@article_bp.route("/articles/<int:article_id>/tags/<int:tag_id>", methods=["DELETE"])
def unbind_tag(article_id, tag_id):
    """Remove the binding between an article and a tag.

    Operates directly on article_tags (db.Table) using SQLAlchemy Core
    delete().  Verifies the binding exists before deleting -- returns 404
    if the article has no such tag bound.

    Success: 200 {"status": "ok", "data": {"message": "Tag unbound"}}
    Errors:  404 article not found | 404 binding not found
    """
    m = _models()

    # Step 1: Verify article exists
    article = _find_article_or_fail(article_id)
    if article is None:
        return _error(f"Article {article_id} not found", 404)

    # Step 2: Check if the binding exists
    check_stmt = (
        select(m.db.func.count())
        .select_from(m.article_tags)
        .where(m.article_tags.c.article_id == article_id)
        .where(m.article_tags.c.tag_id == tag_id)
    )
    count = m.db.session.execute(check_stmt).scalar()

    if count == 0:
        return _error(f"Tag {tag_id} is not bound to article {article_id}", 404)

    # Step 3: Delete from the association table using SQLAlchemy Core
    del_stmt = (
        m.article_tags.delete()
        .where(m.article_tags.c.article_id == article_id)
        .where(m.article_tags.c.tag_id == tag_id)
    )
    m.db.session.execute(del_stmt)
    m.db.session.commit()

    return _ok({"message": "Tag unbound"})

